    async def _handle_chat(self, pid: str, data: Dict[str, Any]):
        text = str(data.get("text") or "")[:MAX_CHAT_LEN]
        if not text:
            return
        async with self._lock:
            p = self.players.get(pid)
            if not p:
                return
            payload = {"type": "chat", "from": {"id": p.id, "name": p.name}, "text": text, "timeMs": now_ms()}
